import{_ as n,o as e,c as o,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"47. Continuing Medical Education Allowance","description":"","frontmatter":{"title":"47. Continuing Medical Education Allowance","eba":"Doctors in Training 2022-2026","topics":["allowances","employment","preliminary","education-pd"]},"headers":[],"relativePath":"ebas/doctors-in-training/education-pd/47-continuing-medical-education-allowance.md","filePath":"ebas/doctors-in-training/education-pd/47-continuing-medical-education-allowance.md"}'),t={name:"ebas/doctors-in-training/education-pd/47-continuing-medical-education-allowance.md"};function c(r,a,l,d,s,p){return e(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="_47-continuing-medical-education-allowance" tabindex="-1">47. Continuing Medical Education Allowance <a class="header-anchor" href="#_47-continuing-medical-education-allowance" aria-label="Permalink to &quot;47. Continuing Medical Education Allowance&quot;">​</a></h1><p><strong>47.1</strong> Doctors are entitled to Continuing Medical Education (CME), paid weekly as an allowance described at <a href="/eba/ebas/doctors-in-training/appendices/2-doctors-in-training-remuneration-allowances-and-deductions.html">Appendix 2</a>, Table 2.1.</p><p><strong>47.2</strong> The CME allowance is payable on a pro-rata basis for part-time Doctors.</p><p><strong>47.3</strong> The CME allowance is payable on a pro-rata basis for casual Doctors who are replacing a person for a specific term for a period of a fortnight or more.</p><p>Plain language terms: CME, CME allowance.</p>',5)])])}const m=n(t,[["render",c]]);export{g as __pageData,m as default};
